import React, { useState, useEffect } from 'react';
import { Search, TrendingUp, TrendingDown, BarChart3, Brain, Volume2, Eye, Star, Activity } from 'lucide-react';
import MetricCard from '../components/MetricCard'
import WelcomeMessage from '../components/WelcomeMessage';
import Sidebar from '../components/Sidebar';
import ChartArea from '../components/ChartArea'
import CompanyItem from '../components/CompanyItem';
import { fetchCompanies } from '../utils/api'



const StockDashboard = () => {
    const [companies, setCompanies] = useState([]);
    const [selectedCompany, setSelectedCompany] = useState(null);
    const [searchTerm, setSearchTerm] = useState("");
    const [isLoading, setIsLoading] = useState(false);


    // ✅ Fetch companies on mount
    useEffect(() => {
        const loadCompanies = async () => {
            setIsLoading(true);
            try {
                const res = await fetchCompanies();
                setCompanies(Array.isArray(res) ? res : []);
            } catch (err) {
                console.error("Error fetching companies:", err);
            } finally {
                setIsLoading(false);
            }
        };
        loadCompanies();
    }, []);


    // ✅ Safe search
    const filteredCompanies = companies.filter(
        (c) =>
            c?.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c?.symbol?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    // ✅ Handle selection
    const handleCompanySelect = (company) => {
        setSelectedCompany(company);
        setIsLoading(true);
        setTimeout(() => setIsLoading(false), 1000); // mock load
    };

    // ✅ Prepare chart data
    const chartData =
        selectedCompany?.historical_data?.length > 0
            ? {
                labels: selectedCompany.historical_data.map((d) => d.date || ""),
                datasets: [
                    {
                        data: selectedCompany.historical_data.map(
                            (d) => Number(d.close || d.price) || 0
                        ),
                        borderColor: "#3b82f6",
                        backgroundColor: "rgba(59, 130, 246, 0.08)",
                        borderWidth: 3,
                        fill: true,
                    },
                ],
            }
            : { labels: [], datasets: [] };



    return (
        <div className="flex h-screen bg-gradient-to-br from-slate-50 to-blue-50">
            {/* Enhanced Sidebar */}
            {/* Sidebar Component */}
            <Sidebar
                companies={companies}
                filteredCompanies={filteredCompanies}
                searchTerm={searchTerm}
                setSearchTerm={setSearchTerm}
                selectedCompany={selectedCompany}
                handleCompanySelect={handleCompanySelect}
            />



            {/* Enhanced Main Panel */}
            <div className="flex-1 flex flex-col">
                {/* Company Info + Metrics */}

                {selectedCompany && (
                    <div className="p-6 bg-white shadow-sm border-b border-gray-200">
                        <div className="flex flex-col xl:flex-row xl:items-center xl:justify-between gap-6">
                            {/* Company Info */}
                            <div className="flex items-center gap-4">
                                <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-2xl flex items-center justify-center text-white font-bold text-xl shadow-lg">
                                    {selectedCompany.symbol?.substring(0, 2)}
                                </div>
                                <div>
                                    <h1 className="text-2xl font-bold text-gray-900 mb-1">
                                        {selectedCompany.name}
                                    </h1>
                                    <div className="flex items-center gap-3 text-sm text-gray-600">
                                        <span className="px-3 py-1 bg-blue-50 text-blue-700 rounded-full font-medium">
                                            {selectedCompany.symbol}
                                        </span>
                                        <span>NSE</span>
                                        <span>•</span>
                                        <span>{selectedCompany.sector}</span>
                                    </div>
                                </div>
                            </div>

                            {/* Metrics */}
                            <div className="grid grid-cols-2 xl:grid-cols-4 gap-4">
                                <MetricCard
                                    label="Current Price"
                                    value={`₹${Number(selectedCompany?.current_price).toFixed(2)}`}
                                    icon={Eye}
                                    subValue={`${Number(selectedCompany?.change) >= 0 ? "+" : ""
                                        }₹${Number(selectedCompany?.change || 0).toFixed(2)} (${Number(
                                            selectedCompany?.change_percent ??
                                            selectedCompany?.changePercent
                                        ).toFixed(2) || "0.00"
                                        }%)`}
                                />
                                <MetricCard
                                    label="Market Cap"
                                    value={selectedCompany?.market_cap || "—"}
                                    icon={BarChart3}
                                    subValue="Total value"
                                />
                                <MetricCard
                                    label="Volume"
                                    value={selectedCompany?.volume || "—"}
                                    icon={Volume2}
                                    subValue="Today's trading"
                                />
                                <MetricCard
                                    label="P/E Ratio"
                                    value={selectedCompany?.pe || "—"}
                                    icon={Activity}
                                    subValue="Price to earnings"
                                />
                            </div>
                        </div>
                    </div>
                )}






                {/* Enhanced Chart Area */}
                <div className="flex-1 p-6">
                    <div className="bg-white rounded-3xl shadow-xl border border-gray-200 h-full flex flex-col overflow-hidden">
                        {selectedCompany ? (
                            <>
                                {/* Chart Header */}
                                <div className="p-6 border-b border-gray-100 bg-gradient-to-r from-gray-50 to-blue-50">
                                    <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                                        <div className="flex items-center gap-3">
                                            <h2 className="text-xl font-bold text-gray-900">Price Chart</h2>
                                            <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-sm font-medium">
                                                Live
                                            </span>
                                        </div>
                                        <div className="flex gap-2">
                                            <ChartArea
                                                selectedCompany={selectedCompany}
                                                isLoading={isLoading}
                                                chartData={chartData}
                                            />
                                        </div>
                                    </div>
                                </div>

                                {/* Chart */}
                                <div className="flex-1 p-6">
                                    {isLoading ? (
                                        <div className="flex flex-col items-center justify-center h-full">
                                            <div className="relative mb-4">
                                                <div className="w-16 h-16 rounded-full border-4 border-blue-200 border-t-blue-600 animate-spin"></div>
                                                <div className="absolute inset-0 w-16 h-16 rounded-full border-4 border-transparent border-r-purple-300 animate-ping"></div>
                                            </div>
                                            <h3 className="text-lg font-semibold text-gray-700 mb-2">Loading Market Data</h3>
                                            <p className="text-gray-500 text-center">Fetching real-time prices and technical indicators...</p>
                                        </div>
                                    ) : (
                                        <Line data={chartData} options={chartOptions} />
                                    )}
                                </div>

                                {/* AI Prediction */}
                                <div className="p-6 bg-gray-50">
                                    <AIPrediction company={stockData[selectedCompany]} isLoading={isLoading} />
                                </div>
                            </>
                        ) : (
                            <WelcomeMessage />
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default StockDashboard;
